import { NextFunction, Response } from 'express';

import { ApiKeyScopeService } from '../services/security/ApiKeyScopeService';
import { logAuditEvent } from '../utils/auditLogger';
import { logger } from '../utils/logger';

import { AuthRequest } from './auth';

const scopeService = new ApiKeyScopeService();

/**
 * API Key Scope Enforcement Middleware
 *
 * Validates that API key holders have the required scope for the endpoint.
 * Only applies to API key authentication (not JWT).
 *
 * Amendment 1: Checks both apiKeyId AND apiKeyScopes (dual-field validation)
 * Amendment 3: Logs detailed API_KEY_SCOPE_DENIED events
 * Amendment 5: Supports phased rollout with grace period (Phase 0)
 * Amendment 6: Returns detailed error response (helps integration debugging)
 *
 * Usage:
 * router.post('/api/v2/activities', requireScope('write:activities'), activityController.create);
 * router.get('/api/v2/activities', requireScope('read:activities'), activityController.list);
 */

/**
 * Phase-based enforcement rollout
 * - Phase 0: Grace period (log violations but allow)
 * - Phase 1: Enforce on activities
 * - Phase 2: Enforce on fleet
 * - Phase 3: Enforce on all endpoints
 *
 * Set via API_KEY_SCOPE_ENFORCEMENT_PHASE environment variable
 */
const API_KEY_SCOPE_ENFORCEMENT_PHASE = Number.parseInt(
  process.env.API_KEY_SCOPE_ENFORCEMENT_PHASE ?? '1',
  10
);

/**
 * Create middleware that validates API key scopes.
 *
 * Amendment 1: Check both apiKeyId AND apiKeyScopes (defensive)
 *
 * @param required - The scope required for this endpoint (e.g., 'write:activities')
 * @param phaseRequired - The minimum enforcement phase for this endpoint (1 = activities, 2 = fleet, etc.)
 * @returns Express middleware
 */
export const requireScope =
  (required: string, phaseRequired: number = 1) =>
  async (req: AuthRequest, res: Response, next: NextFunction): Promise<void> => {
    try {
      // Amendment 1: Check both apiKeyId AND apiKeyScopes (not just one)
      const isApiKeyAuth = req.user?.apiKeyId !== undefined && req.user?.apiKeyScopes !== undefined;

      if (!isApiKeyAuth) {
        // JWT auth or other method, skip scope validation
        next();
        return;
      }

      const hasScope = scopeService.hasScope(req.user!.apiKeyScopes, required);

      if (!hasScope) {
        const currentPhase = API_KEY_SCOPE_ENFORCEMENT_PHASE;

        // Amendment 5: Grace period (Phase 0) — log but don't enforce
        if (currentPhase === 0) {
          logger.warn(
            `[API_KEY_SCOPE_GRACE_PERIOD] API key would lack scope: ` +
              `user=${req.user!.id}, key=${req.user!.apiKeyId}, ` +
              `required=${required}, granted=${req.user!.apiKeyScopes?.join(',')}`
          );

          // Allow for now (grace period)
          next();
          return;
        }

        // Amendment 5: Enforcement phase — enforce if current phase >= required phase
        if (currentPhase >= phaseRequired) {
          // Amendment 3: Log detailed API_KEY_SCOPE_DENIED event
          logAuditEvent({
            eventType: 'API_KEY_SCOPE_DENIED',
            userId: req.user!.id,
            organizationId: req.user!.currentOrganizationId,
            apiKeyId: req.user!.apiKeyId,
            details: {
              requiredScope: required,
              availableScopes: req.user!.apiKeyScopes,
              endpoint: `${req.method} ${req.path}`,
              ipAddress: req.ip,
              userAgent: req.headers['user-agent'],
            },
          } as any);

          logger.warn(
            `API key scope denied: user=${req.user!.id}, key=${req.user!.apiKeyId}, ` +
              `endpoint=${req.method} ${req.path}, required=${required}`
          );

          // Amendment 6: Return detailed error (helps integration debugging)
          res.status(403).json({
            message: 'API key does not have required scope',
            code: 'INSUFFICIENT_SCOPE',
            required,
            granted: req.user!.apiKeyScopes,
          });
          return;
        }

        // Future phase: allow for now (enforcement not yet enabled)
        next();
        return;
      }

      // Scope is valid, proceed
      next();
    } catch (error) {
      logger.error('API key scope validation error:', error);
      res.status(500).json({ message: 'Internal server error' });
    }
  };

/**
 * Reset enforcement phase for testing purposes.
 * Used to simulate different rollout phases in tests.
 *
 * @param phase - The phase to set (0-3)
 * @internal Testing only
 */
export const __setApiKeyScopePhaseForTests = (phase: number): void => {
  // Note: In production, API_KEY_SCOPE_ENFORCEMENT_PHASE is set via env var
  // This function is for unit testing only
  (global as any).__API_KEY_SCOPE_ENFORCEMENT_PHASE_OVERRIDE = phase;
};

export const __resetApiKeyScopePhaseForTests = (): void => {
  delete (global as any).__API_KEY_SCOPE_ENFORCEMENT_PHASE_OVERRIDE;
};
